class TransactionProcessor {
    static let shared = TransactionProcessor()
    private let secureStorage = SecureStorageManager.shared
    private let queue = DispatchQueue(label: "com.bankingapp.transactions", qos: .userInitiated)
    
    private init() {}
    
    func processTransaction(_ transaction: Transaction, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        queue.async {
            guard self.validateTransaction(transaction) else {
                DispatchQueue.main.async {
                    completion(.failure(.validationFailed))
                }
                return
            }
            
            guard self.checkSufficientFunds(accountNumber: transaction.fromAccount, amount: transaction.amount) else {
                DispatchQueue.main.async {
                    completion(.failure(.insufficientFunds))
                }
                return
            }
            
            guard self.checkTransactionLimits(transaction) else {
                DispatchQueue.main.async {
                    completion(.failure(.limitExceeded))
                }
                return
            }
            
            let processedTransaction = self.executeTransaction(transaction)
            
            do {
                try self.logTransaction(processedTransaction)
                DispatchQueue.main.async {
                    completion(.success(processedTransaction))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.processingError))
                }
            }
        }
    }
    
    private func validateTransaction(_ transaction: Transaction) -> Bool {
        guard transaction.amount > 0 else { return false }
        guard !transaction.fromAccount.isEmpty, !transaction.toAccount.isEmpty else { return false }
        guard transaction.fromAccount != transaction.toAccount else { return false }
        return true
    }
    
    private func checkSufficientFunds(accountNumber: String, amount: Decimal) -> Bool {
        if let account = AccountManager.shared.getAccount(accountNumber: accountNumber) {
            return account.balance >= amount
        }
        return false
    }
    
    private func checkTransactionLimits(_ transaction: Transaction) -> Bool {
        let dailyLimit: Decimal = 10000.00
        return transaction.amount <= dailyLimit
    }
    
    private func executeTransaction(_ transaction: Transaction) -> Transaction {
        AccountManager.shared.debitAccount(accountNumber: transaction.fromAccount, amount: transaction.amount)
        AccountManager.shared.creditAccount(accountNumber: transaction.toAccount, amount: transaction.amount)
        
        var processedTransaction = transaction
        processedTransaction = Transaction(
            id: transaction.id,
            fromAccount: transaction.fromAccount,
            toAccount: transaction.toAccount,
            amount: transaction.amount,
            currency: transaction.currency,
            timestamp: Date(),
            type: transaction.type,
            status: .completed,
            description: transaction.description
        )
        
        return processedTransaction
    }
    
    private func logTransaction(_ transaction: Transaction) throws {
