            self.accounts[account.accountNumber] = account
            self.saveAccounts()
        }
    }
    
    func getAccount(accountNumber: String) -> Account? {
        return queue.sync {
            return accounts[accountNumber]
        }
    }
    
    func getAllAccounts() -> [Account] {
        return queue.sync {
            return Array(accounts.values)
        }
    }
    
    func updateAccountBalance(accountNumber: String, newBalance: Decimal) {
        queue.async(flags: .barrier) {
            if var account = self.accounts[accountNumber] {
                account.balance = newBalance
                self.accounts[accountNumber] = account
                self.saveAccounts()
            }
        }
    }
    
    func debitAccount(accountNumber: String, amount: Decimal) {
        queue.async(flags: .barrier) {
            if var account = self.accounts[accountNumber] {
                account.balance -= amount
                self.accounts[accountNumber] = account
                self.saveAccounts()
            }
        }
    }
    
    func creditAccount(accountNumber: String, amount: Decimal) {
        queue.async(flags: .barrier) {
            if var account = self.accounts[accountNumber] {
                account.balance += amount
                self.accounts[accountNumber] = account
                self.saveAccounts()
            }
        }
    }
    
    private func saveAccounts() {
        do {
            let encoder = JSONEncoder()
            let accountsArray = Array(accounts.values)
            let data = try encoder.encode(accountsArray)
            try secureStorage.saveSecureData(data, forKey: "userAccounts")
        } catch {
