    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadAccounts()
    }
    
    private func setupUI() {
        title = "Account Balances"
        view.backgroundColor = .systemBackground
        
        tableView.frame = view.bounds
        tableView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(AccountBalanceCell.self, forCellReuseIdentifier: "AccountCell")
        
        refreshControl.addTarget(self, action: #selector(refreshAccounts), for: .valueChanged)
        tableView.refreshControl = refreshControl
        
        view.addSubview(tableView)
        
        let addButton = UIBarButtonItem(barButtonSystemItem: .add, target: self, action: #selector(addNewAccount))
        navigationItem.rightBarButtonItem = addButton
    }
    
    private func loadAccounts() {
        accounts = AccountManager.shared.getAllAccounts()
        tableView.reloadData()
    }
    
    @objc private func refreshAccounts() {
        loadAccounts()
        refreshControl.endRefreshing()
    }
    
    @objc private func addNewAccount() {
        let alert = UIAlertController(title: "Add Account", message: "Enter account details", preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Account Number"
        }
        alert.addTextField { textField in
            textField.placeholder = "Account Holder Name"
        }
        alert.addTextField { textField in
            textField.placeholder = "Initial Balance"
            textField.keyboardType = .decimalPad
        }
        
        let addAction = UIAlertAction(title: "Add", style: .default) { _ in
            guard let accountNumber = alert.textFields?[0].text,
                  let holderName = alert.textFields?[1].text,
                  let balanceText = alert.textFields?[2].text,
                  let balance = Decimal(string: balanceText) else {
                return
            }
            
            let newAccount = Account(
                accountNumber: accountNumber,
                accountHolderName: holderName,
                balance: balance,
                currency: "USD",
                accountType: .checking
            )
            
            AccountManager.shared.addAccount(newAccount)
            self.loadAccounts()
        }
        
        alert.addAction(addAction)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        
        present(alert, animated: true)
    }
}

