        ])
    }
    
    @objc private func performTransfer() {
        view.endEditing(true)
        
        guard let toAccount = toAccountField.text, !toAccount.isEmpty,
              let amountText = amountField.text, let amount = Decimal(string: amountText) else {
            showAlert(title: "Error", message: "Please fill in all required fields")
            return
        }
        
        let transaction = Transaction(
            id: UUID().uuidString,
            fromAccount: fromAccount.accountNumber,
            toAccount: toAccount,
            amount: amount,
            currency: fromAccount.currency,
            timestamp: Date(),
            type: .transfer,
            status: .pending,
            description: descriptionField.text
        )
        
        transferButton.isEnabled = false
        
        TransactionProcessor.shared.processTransaction(transaction) { [weak self] result in
            guard let self = self else { return }
            
            self.transferButton.isEnabled = true
            
            switch result {
            case .success(let completedTransaction):
                self.showAlert(title: "Success", message: "Transfer completed successfully\nTransaction ID: \(completedTransaction.id)") {
                    self.navigationController?.popViewController(animated: true)
                }
            case .failure(let error):
                var message = "Transfer failed"
                switch error {
                case .insufficientFunds:
                    message = "Insufficient funds in account"
                case .validationFailed:
                    message = "Transaction validation failed"
                case .limitExceeded:
                    message = "Transaction limit exceeded"
                case .processingError:
                    message = "Error processing transaction"
                case .accountNotFound:
                    message = "Account not found"
                }
                self.showAlert(title: "Error", message: message)
            }
        }
    }
    
    private func showAlert(title: String, message: String, completion: (() -> Void)? = nil) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completion?()
        })
        present(alert, animated: true)
    }
}

class TransactionHistoryViewController: UIViewController {
    private let tableView = UITableView()
    private var transactions: [Transaction] = []
    private let refreshControl = UIRefreshControl()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadTransactions()
    }
    
    private func setupUI() {
        title = "Transaction History"
        view.backgroundColor = .systemBackground
        
        tableView.frame = view.bounds
        tableView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(TransactionCell.self, forCellReuseIdentifier: "TransactionCell")
        
        refreshControl.addTarget(self, action: #selector(refreshTransactions), for: .valueChanged)
        tableView.refreshControl = refreshControl
        
        view.addSubview(tableView)
    }
    
    private func loadTransactions() {
        transactions = TransactionProcessor.shared.retrieveTransactionHistory()
        transactions.sort { $0.timestamp > $1.timestamp }
        tableView.reloadData()
    }
    
    @objc private func refreshTransactions() {
        loadTransactions()
        refreshControl.endRefreshing()
    }
}

extension TransactionHistoryViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return transactions.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath) as! TransactionCell
        let transaction = transactions[indexPath.row]
        cell.configure(with: transaction)
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 90
    }
}

class TransactionCell: UITableViewCell {
    private let typeLabel = UILabel()
    private let amountLabel = UILabel()
    private let accountLabel = UILabel()
    private let dateLabel = UILabel()
    private let statusLabel = UILabel()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupUI()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupUI() {
        typeLabel.font = .systemFont(ofSize: 16, weight: .semibold)
        amountLabel.font = .systemFont(ofSize: 18, weight: .bold)
        accountLabel.font = .systemFont(ofSize: 14, weight: .regular)
        accountLabel.textColor = .secondaryLabel
        dateLabel.font = .systemFont(ofSize: 12, weight: .regular)
        dateLabel.textColor = .secondaryLabel
        statusLabel.font = .systemFont(ofSize: 12, weight: .medium)
        
        let stackView = UIStackView(arrangedSubviews: [typeLabel, accountLabel, dateLabel])
        stackView.axis = .vertical
        stackView.spacing = 4
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        amountLabel.translatesAutoresizingMaskIntoConstraints = false
        statusLabel.translatesAutoresizingMaskIntoConstraints = false
        
        contentView.addSubview(stackView)
        contentView.addSubview(amountLabel)
        contentView.addSubview(statusLabel)
        
        NSLayoutConstraint.activate([
            stackView.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            stackView.centerYAnchor.constraint(equalTo: contentView.centerYAnchor),
            
            amountLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            amountLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 16),
            
            statusLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            statusLabel.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -16)
        ])
    }
    
    func configure(with transaction: Transaction) {
        switch transaction.type {
        case .transfer:
            typeLabel.text = "Transfer"
        case .deposit:
            typeLabel.text = "Deposit"
        case .withdrawal:
            typeLabel.text = "Withdrawal"
        case .payment:
            typeLabel.text = "Payment"
        }
        
        accountLabel.text = "To: \(transaction.toAccount)"
        
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        dateLabel.text = formatter.string(from: transaction.timestamp)
        
        amountLabel.text = "\(transaction.currency) \(transaction.amount)"
        
        switch transaction.status {
        case .completed:
            amountLabel.textColor = .systemGreen
            statusLabel.text = "✓ Completed"
            statusLabel.textColor = .systemGreen
        case .pending:
            amountLabel.textColor = .systemOrange
            statusLabel.text = "⏱ Pending"
            statusLabel.textColor = .systemOrange
        case .failed:
            amountLabel.textColor = .systemRed
            statusLabel.text = "✗ Failed"
            statusLabel.textColor = .systemRed
        case .cancelled:
            amountLabel.textColor = .systemGray
            statusLabel.text = "Cancelled"
            statusLabel.textColor = .systemGray
        }
    }
}

